function QuizGeneratorWidget() {
  const questions = [
    { q: 'What is the time complexity of binary search?', options: ['O(n)', 'O(log n)', 'O(n^2)', 'O(1)'], a: 1 },
    { q: 'Which protocol is connectionless?', options: ['TCP', 'HTTP', 'UDP', 'FTP'], a: 2 },
    { q: 'What does CSS stand for?', options: ['Computer Style Sheets', 'Cascading Style Sheets', 'Creative Style System', 'Colorful Style Sheets'], a: 1 }
  ];
  const [current, setCurrent] = React.useState(0);
  const [score, setScore] = React.useState(0);
  const [finished, setFinished] = React.useState(false);
  const [selected, setSelected] = React.useState(null);

  function choose(optionIndex) {
    if (selected !== null) return;
    setSelected(optionIndex);
    if (optionIndex === questions[current].a) {
      setScore(score + 1);
    }
    setTimeout(() => {
      if (current + 1 < questions.length) {
        setCurrent(current + 1);
        setSelected(null);
      } else {
        setFinished(true);
      }
    }, 800);
  }

  function restart() {
    setCurrent(0);
    setScore(0);
    setFinished(false);
    setSelected(null);
  }

  if (finished) {
    return (
      <div style={{ fontFamily: 'system-ui, sans-serif', padding: 16, background: '#0f172a', color: '#e2e8f0', borderRadius: 12, height: '100%', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center' }}>
        <h3 style={{ margin: 0, marginBottom: 12 }}>Quiz Complete</h3>
        <div style={{ fontSize: 28, fontWeight: 700, color: '#22c55e', marginBottom: 8 }}>{score}/{questions.length}</div>
        <button onClick={restart} style={{ padding: '10px 20px', borderRadius: 8, border: 'none', background: '#3b82f6', color: '#fff', fontWeight: 600, cursor: 'pointer', fontFamily: 'system-ui, sans-serif' }}>Retry</button>
      </div>
    );
  }

  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', padding: 16, background: '#0f172a', color: '#e2e8f0', borderRadius: 12, height: '100%', display: 'flex', flexDirection: 'column' }}>
      <h3 style={{ margin: 0, marginBottom: 10 }}>Quiz</h3>
      <div style={{ fontSize: 13, marginBottom: 12 }}>Q{current + 1}: {questions[current].q}</div>
      <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
        {questions[current].options.map((opt, i) => {
          let bg = '#1e293b';
          if (selected !== null) {
            if (i === questions[current].a) bg = '#166534';
            else if (i === selected) bg = '#7f1d1d';
          }
          return (
            <button
              key={i}
              onClick={() => choose(i)}
              style={{
                textAlign: 'left',
                padding: 10,
                borderRadius: 8,
                border: 'none',
                background: bg,
                color: '#e2e8f0',
                cursor: selected !== null ? 'default' : 'pointer',
                fontFamily: 'system-ui, sans-serif',
                fontSize: 13
              }}
            >
              {opt}
            </button>
          );
        })}
      </div>
    </div>
  );
}
render(<QuizGeneratorWidget/>);
